/**
 * MedX alert runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Inline alerts for cold-chain breaches, stock warnings, and system notices.
 */
const ALERT_VARIANTS = Object.freeze({
  info: { icon: "info", border: "border-blue-500/30", bg: "bg-blue-500/10" },
  success: { icon: "check-circle", border: "border-emerald-500/30", bg: "bg-emerald-500/10" },
  warning: { icon: "alert-triangle", border: "border-amber-500/30", bg: "bg-amber-500/10" },
  destructive: { icon: "x-circle", border: "border-destructive/30", bg: "bg-destructive/10" },
});

const ALERT_TEMPLATES = Object.freeze({
  coldChainBreach: {
    variant: "destructive",
    title: "Cold chain breach",
    description: "Temperature in West Cold Storage exceeded 8°C for 12 minutes. Review affected lots.",
  },
  lowStock: {
    variant: "warning",
    title: "Low stock alert",
    description: "SKU-3011 Insulin Pens below reorder point (340 / 500 units).",
  },
  syncComplete: {
    variant: "success",
    title: "Sync complete",
    description: "Blockchain traceability records updated successfully.",
  },
  maintenanceWindow: {
    variant: "info",
    title: "Scheduled maintenance",
    description: "Dashboard read-only mode tonight 02:00–04:00 UTC.",
  },
  complianceReview: {
    variant: "warning",
    title: "Compliance review due",
    description: "Supplier MedSupply Global certification expires in 14 days.",
  },
});

const alertQueue = [];
const dismissedAlerts = new Set();
let alertIdSeq = 0;

function createAlert(config) {
  const template = config.template ? ALERT_TEMPLATES[config.template] : null;
  const variant = config.variant ?? template?.variant ?? "info";
  const alert = {
    id: config.id ?? `medx-alert-${++alertIdSeq}`,
    variant,
    styles: ALERT_VARIANTS[variant] ?? ALERT_VARIANTS.info,
    title: config.title ?? template?.title ?? "Alert",
    description: config.description ?? template?.description ?? "",
    dismissible: config.dismissible ?? true,
    action: config.action ?? null,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    dismissed: false,
  };
  alertQueue.push(alert);
  return alert;
}

function dismissAlert(id) {
  const alert = alertQueue.find((a) => a.id === id);
  if (!alert || alert.dismissed) return false;
  alert.dismissed = true;
  alert.dismissedAt = Date.now();
  dismissedAlerts.add(id);
  return true;
}

function getActiveAlerts() {
  return alertQueue.filter((a) => !a.dismissed);
}

function getAlertsByVariant(variant) {
  return getActiveAlerts().filter((a) => a.variant === variant);
}

function prioritizeAlerts() {
  const priority = { destructive: 0, warning: 1, info: 2, success: 3 };
  return getActiveAlerts().sort(
    (a, b) => (priority[a.variant] ?? 99) - (priority[b.variant] ?? 99),
  );
}

async function runMedxAlert() {
  console.log("[medx:ui:alert] runtime initialized");
  console.log(`[medx:ui:alert] variants=${Object.keys(ALERT_VARIANTS).length} templates=${Object.keys(ALERT_TEMPLATES).length}`);

  createAlert({ template: "coldChainBreach", metadata: { sensorId: "TEMP-WEST-03" } });
  createAlert({ template: "lowStock" });
  createAlert({ template: "syncComplete" });
  createAlert({ template: "maintenanceWindow" });
  createAlert({ template: "complianceReview" });

  const prioritized = prioritizeAlerts();
  dismissAlert(prioritized[prioritized.length - 1]?.id);

  console.log(`[medx:ui:alert] total=${alertQueue.length} active=${getActiveAlerts().length}`);
  console.log(`[medx:ui:alert] critical=${getAlertsByVariant("destructive").length}`);
  console.log("[medx:ui:alert] topPriority", prioritized[0]?.title);
  console.log("[medx:ui:alert] bootstrap complete");
}

module.exports = runMedxAlert;
